// The previous attempt asserted facts (e.g. `post1_self_@[p as int]
// =~= pre_self_@[p as int]`) that are part of the *antecedent* of this
// synthetic proof fn's ensures clause — i.e. they are NOT requires of
// `det_<f>` and therefore not available as hypotheses anywhere inside
// the body. They only become hypotheses at function exit, when Verus
// discharges the implication `(ensures_conj) ==> det_<f>_equal(...)`.
//
// To make the ensures-conjuncts usable in the body, wrap the entire
// derivation in `if (ensures_conjunction) { ... }`. Inside the `if`,
// the conjunction is a hypothesis, so we can (a) instantiate both
// `forall|p|` ensures-foralls on the same `p` (closing the disjoint-
// trigger gap), and (b) chain each per-projection equality at the
// `ioid` slot through `pre_self_@[ioid as int].unwrap()`. Verus then
// remembers each `assert` inside the `if` as `ensures_conj ==> assert`
// outside the `if`. At function exit, the synthetic ensures-antecedent
// supplies `ensures_conj`, so z3 has every per-projection equality it
// needs to discharge `det_<f>_equal`.
if post1_self_.wf()
    && (forall|p: IOid|
        #![trigger post1_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < IOID_MAX && p != ioid ==> post1_self_@[p as int] =~= pre_self_@[p as int])
    && post1_self_@[ioid as int].is_Some()
    && post1_self_@[ioid as int].unwrap().wf()
    && post1_self_@[ioid as int].unwrap().ioid == pre_self_@[ioid as int].unwrap().ioid
    && post1_self_@[ioid as int].unwrap().kernel_l4_end == pre_self_@[ioid as int].unwrap().kernel_l4_end
    && post1_self_@[ioid as int].unwrap().page_closure() =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr)
    && post1_self_@[ioid as int].unwrap().mapping_4k() =~= pre_self_@[ioid as int].unwrap().mapping_4k()
    && post1_self_@[ioid as int].unwrap().mapping_2m() =~= pre_self_@[ioid as int].unwrap().mapping_2m()
    && post1_self_@[ioid as int].unwrap().mapping_1g() =~= pre_self_@[ioid as int].unwrap().mapping_1g()
    && post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i) == pre_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i)
    && post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).is_Some()
    && post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).get_Some_0().addr == page_map_ptr
    && post1_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i).is_None()
    && post1_self_@[ioid as int].unwrap().kernel_entries =~= pre_self_@[ioid as int].unwrap().kernel_entries
    && post2_self_.wf()
    && (forall|p: IOid|
        #![trigger post2_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < IOID_MAX && p != ioid ==> post2_self_@[p as int] =~= pre_self_@[p as int])
    && post2_self_@[ioid as int].is_Some()
    && post2_self_@[ioid as int].unwrap().wf()
    && post2_self_@[ioid as int].unwrap().ioid == pre_self_@[ioid as int].unwrap().ioid
    && post2_self_@[ioid as int].unwrap().kernel_l4_end == pre_self_@[ioid as int].unwrap().kernel_l4_end
    && post2_self_@[ioid as int].unwrap().page_closure() =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr)
    && post2_self_@[ioid as int].unwrap().mapping_4k() =~= pre_self_@[ioid as int].unwrap().mapping_4k()
    && post2_self_@[ioid as int].unwrap().mapping_2m() =~= pre_self_@[ioid as int].unwrap().mapping_2m()
    && post2_self_@[ioid as int].unwrap().mapping_1g() =~= pre_self_@[ioid as int].unwrap().mapping_1g()
    && post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i) == pre_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i)
    && post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).is_Some()
    && post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).get_Some_0().addr == page_map_ptr
    && post2_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i).is_None()
    && post2_self_@[ioid as int].unwrap().kernel_entries =~= pre_self_@[ioid as int].unwrap().kernel_entries
    {
        // Force both per-slot `forall|p|`s to fire on the same `p` and
        // chain them through `pre_self_@[p as int]`.
        assert forall|p: IOid| 0 <= p < IOID_MAX && p != ioid implies
            post1_self_@[p as int] =~= post2_self_@[p as int] by {
            assert(post1_self_@[p as int] =~= pre_self_@[p as int]);
            assert(post2_self_@[p as int] =~= pre_self_@[p as int]);
        }

        // Per-projection equalities at the `ioid` slot: each side equals
        // the same `pre_self_@[ioid as int].unwrap()`-derived value, so
        // they equal each other.
        assert(post1_self_@[ioid as int].unwrap().ioid
            == post2_self_@[ioid as int].unwrap().ioid);
        assert(post1_self_@[ioid as int].unwrap().kernel_l4_end
            == post2_self_@[ioid as int].unwrap().kernel_l4_end);
        assert(post1_self_@[ioid as int].unwrap().page_closure()
            =~= post2_self_@[ioid as int].unwrap().page_closure());
        assert(post1_self_@[ioid as int].unwrap().mapping_4k()
            =~= post2_self_@[ioid as int].unwrap().mapping_4k());
        assert(post1_self_@[ioid as int].unwrap().mapping_2m()
            =~= post2_self_@[ioid as int].unwrap().mapping_2m());
        assert(post1_self_@[ioid as int].unwrap().mapping_1g()
            =~= post2_self_@[ioid as int].unwrap().mapping_1g());
        assert(post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i)
            == post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i));
        assert(post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).is_Some());
        assert(post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).is_Some());
        assert(post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).get_Some_0().addr
            == post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l3(target_l4i, target_l3i).get_Some_0().addr);
        assert(post1_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i).is_None());
        assert(post2_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i).is_None());
        assert(post1_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i)
            == post2_self_@[ioid as int].unwrap().spec_resolve_mapping_1g_l3(target_l4i, target_l3i));
        assert(post1_self_@[ioid as int].unwrap().kernel_entries
            =~= post2_self_@[ioid as int].unwrap().kernel_entries);

        // Both slots at `ioid` are `Some`; the per-projection equalities
        // above pin the visible structure of the `unwrap()`'d PageTable.
        assert(post1_self_@[ioid as int].is_Some());
        assert(post2_self_@[ioid as int].is_Some());
    }

// Returns are `()`, trivially equal.
assert(r1 == r2);
